import{_ as s,C as t,o as h,c as p,j as a,a as o,E as i,a3 as c}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第45章 观道","description":"帛书道篇第45章 · 观道（通行本第1章）","frontmatter":{"title":"帛书第45章 观道","description":"帛书道篇第45章 · 观道（通行本第1章）","category":"guide","aliases":["帛书第45章","马王堆老子45","通行本第1章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing-boshu/chapter-45.md","filePath":"daoism/texts/dao-de-jing-boshu/chapter-45.md","lastUpdated":1779783531000}'),u={name:"daoism/texts/dao-de-jing-boshu/chapter-45.md"};function m(x,e,b,_,g,f){const n=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),l=t("DaoLineGuide"),d=t("DaoKeywordCards");return h(),p("div",null,[e[0]||(e[0]=a("h1",{id:"帛书老子第45章",tabindex:"-1"},[o("帛书老子第45章 "),a("a",{class:"header-anchor",href:"#帛书老子第45章","aria-label":'Permalink to "帛书老子第45章"'},"​")],-1)),i(n,{title:"第45章 观道",summary:"本章出自马王堆帛书《老子》甲本道篇，对应通行本第1章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 道篇第45章"},{label:"对照",text:"通行本第1章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[o("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(r,{paragraphs:["道可道也 非恒道也","名可名也 非恒名也","无名万物之始也","有名万物之母也","故恒无欲也 以观亓眇 恒有欲也 以观亓所徼","两者同出 异名同谓 玄之又玄 众眇之门"]}),i(l,{lines:[{text:"道可道也 非恒道也",tone:"起句",guide:"可以说出来的道，就不是恒常的道。帛书作「恒」而非「常」，是通行本避汉文帝刘恒讳所改——一字之差，牵动全文。"},{text:"名可名也 非恒名也",tone:"并进",guide:"可以命名的名，就不是恒常的名。道与名并举，先破语言对终极真实的限定。"},{text:"无名万物之始也",tone:"溯源",guide:"无名，指向万物尚未被命名、未被概念切割的源初状态。帛书「万物之始」与通行本「天地之始」有异。"},{text:"有名万物之母也",tone:"展开",guide:"有名，万物开始被识别、被区分、被命名——世界由此展开为可分可识的样态。"},{text:"故恒无欲也 以观亓眇",tone:"观法一",guide:"常保持无欲的心态，去观照道的幽微精妙。「眇」通「妙」，帛书用字更古——无欲才能看见深处。"},{text:"恒有欲也 以观亓所徼",tone:"观法二",guide:"带着有欲的心去看，看道在万物中显现的边界与端倪。「徼」即边际——有欲才能看见轮廓。"},{text:"两者同出 异名同谓",tone:"合拢",guide:"无欲之观与有欲之观，看似两种方向，实同出一源，只是名称不同——帛书「异名同谓」一语破的。"},{text:"玄之又玄 众眇之门",tone:"收束",guide:"深远之上再深远——不是故弄玄虚，而是说：愿意不断往深处走，那便是进入一切精妙的门。「眇」即「妙」，帛书以眇为妙。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[o("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(d,{items:[{term:"恒",pinyin:["héng"],explanation:"帛书甲本作「恒」，通行本因避汉文帝刘恒讳改「常」。恒道即永恒不变的道，比「常」更强调不变之本体。这是帛书本与通行本最显著的差别之一。"},{term:"眇",pinyin:["miǎo"],explanation:"通「妙」，精微、幽深。「观亓眇」即观其微妙。帛书用「眇」而不用「妙」，保留了更古的字形。"},{term:"徼",pinyin:["jiào"],explanation:"边际、端倪、轮廓。「观亓所徼」即观其显现出来的边界。无欲可观其深远，有欲可观其形迹。"},{term:"谓",pinyin:["wèi"],explanation:"称谓、称呼。「异名同谓」——名称虽然不同（无/有、眇/徼），但所指称的是同一个东西。帛书此句比通行本更简洁直接。"},{term:"亓",pinyin:["qí"],explanation:"帛书古字，通「其」。帛书甲本大量使用「亓」而非「其」，是战国至汉初的常用写法。"}]}),e[3]||(e[3]=c('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「观道」，帛书此章围绕「道可道非恒道」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第1章，所属帛书道篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const k=s(u,[["render",m]]);export{q as __pageData,k as default};
